using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(IServiceProvider serviceProvider) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync(string? statusFilter = null, string? search = null)
    {
        using var scope = serviceProvider.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();

        var query = db.Shipments.AsQueryable();

        if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, true, out var status))
        {
            query = query.Where(s => s.Status == status);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.ToLower();
            query = query.Where(s =>
                s.TrackingNumber.ToLower().Contains(term) ||
                s.Destination.ToLower().Contains(term) ||
                s.RecipientName.ToLower().Contains(term) ||
                s.Origin.ToLower().Contains(term));
        }

        return await query.OrderByDescending(s => s.ShippedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        using var scope = serviceProvider.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        return await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment?> GetShipmentByIdAsync(int id)
    {
        using var scope = serviceProvider.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        return await db.Shipments.FindAsync(id);
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        using var scope = serviceProvider.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
            if (newStatus == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
            await db.SaveChangesAsync();
        }
    }
}

