app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseHttpsRedirection();

app.UseAntiforgery();

// Shipment API endpoints (used by the WebAssembly client)
app.MapGet("api/shipments", async (IShipmentService svc, string? status, string? search) =>
    Results.Ok(await svc.GetAllShipmentsAsync(status, search)))
    .RequireAuthorization();

app.MapGet("api/shipments/{id:int}", async (IShipmentService svc, int id) =>
{
    var shipment = await svc.GetShipmentByIdAsync(id);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
}).RequireAuthorization();

app.MapGet("api/shipments/track/{trackingNumber}", async (IShipmentService svc, string trackingNumber) =>
{
    var shipment = await svc.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
});

app.MapPut("api/shipments/{id:int}/status", async (IShipmentService svc, int id, ShipmentStatus newStatus) =>
{
    await svc.UpdateShipmentStatusAsync(id, newStatus);
    return Results.NoContent();
}).RequireAuthorization();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);

// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

app.Run();

