@page "/"

<PageTitle>ShipmentTracker — Track Your Shipment</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-5 fw-bold">📦 Shipment Tracker</h1>
    <p class="lead text-muted">Enter your tracking number to see real-time shipment status and estimated delivery.</p>
</div>

<div class="row justify-content-center">
    <div class="col-md-6">
        <div class="input-group input-group-lg mb-3">
            <input type="text" class="form-control" placeholder="e.g. TRK-2026-001"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>

        @if (errorMessage is not null)
        {
            <div class="alert alert-warning">@errorMessage</div>
        }

        @if (shipment is not null)
        {
            <div class="card shadow-sm">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>@shipment.TrackingNumber</strong>
                    <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                </div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-5">Recipient</dt>
                        <dd class="col-sm-7">@shipment.RecipientName</dd>

                        <dt class="col-sm-5">Origin</dt>
                        <dd class="col-sm-7">@shipment.Origin</dd>

                        <dt class="col-sm-5">Destination</dt>
                        <dd class="col-sm-7">@shipment.Destination</dd>

                        <dt class="col-sm-5">Shipped</dt>
                        <dd class="col-sm-7">@shipment.ShippedDate.ToString("MMM dd, yyyy")</dd>

                        <dt class="col-sm-5">Estimated Delivery</dt>
                        <dd class="col-sm-7">@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt class="col-sm-5">Delivered</dt>
                            <dd class="col-sm-7">@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }

                        <dt class="col-sm-5">Description</dt>
                        <dd class="col-sm-7">@shipment.Description</dd>
                    </dl>
                </div>
            </div>
        }
    </div>
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private string trackingNumber = string.Empty;
    private Shipment? shipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        errorMessage = null;
        shipment = null;

        if (string.IsNullOrWhiteSpace(trackingNumber))
        {
            errorMessage = "Please enter a tracking number.";
            return;
        }

        isLoading = true;
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
            if (shipment is null)
                errorMessage = $"No shipment found for \"{trackingNumber.Trim()}\".";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}

