+        <input type="text" class="form-control" placeholder="Search tracking #, destination, recipient…"
+               @bind="searchTerm" @bind:event="oninput" @onkeydown="HandleSearchKeyDown" />
+    </div>
+    <div class="col-md-3">
+        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
+            <option value="">All Statuses</option>
+            @foreach (var s in Enum.GetValues<ShipmentStatus>())
+            {
+                <option value="@s">@s</option>
+            }
+        </select>
+    </div>
+    <div class="col-md-2">
+        <button class="btn btn-outline-primary w-100" @onclick="LoadShipments">
+            🔍 Filter
+        </button>
+    </div>
+</div>
+
+@if (isLoading)
+{
+    <div class="text-center py-4">
+        <div class="spinner-border text-primary" role="status">
+            <span class="visually-hidden">Loading…</span>
+        </div>
+    </div>
+}
+else if (shipments is null || shipments.Count == 0)
+{
+    <div class="alert alert-info">No shipments found.</div>
+}
+else
+{
+    <div class="table-responsive">
+        <table class="table table-striped table-hover align-middle">
+            <thead class="table-dark">
+                <tr>
+                    <th>Tracking #</th>
+                    <th>Recipient</th>
+                    <th>Origin</th>
+                    <th>Destination</th>
+                    <th>Status</th>
+                    <th>Est. Delivery</th>
+                    <th>Actions</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var s in shipments)
+                {
+                    <tr>
+                        <td><code>@s.TrackingNumber</code></td>
+                        <td>@s.RecipientName</td>
+                        <td>@s.Origin</td>
+                        <td>@s.Destination</td>
+                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
+                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
+                        <td>
+                            @if (editingShipmentId == s.Id)
+                            {
+                                <div class="d-flex gap-1">
+                                    <select class="form-select form-select-sm" style="width: auto;"
+                                            @bind="newStatus">
+                                        @foreach (var st in Enum.GetValues<ShipmentStatus>())
+                                        {
+                                            <option value="@st">@st</option>
+                                        }
+                                    </select>
+                                    <button class="btn btn-sm btn-success" @onclick="() => SaveStatus(s)">✓</button>
+                                    <button class="btn btn-sm btn-outline-secondary" @onclick="CancelEdit">✗</button>
+                                </div>
+                            }
+                            else
+                            {
+                                <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(s)">
+                                    Update Status
+                                </button>
+                            }
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+}
+
+@code {
+    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
+
+    private List<Shipment>? shipments;
+    private string searchTerm = string.Empty;
+    private string statusFilter = string.Empty;
+    private bool isLoading;
+    private int? editingShipmentId;
+    private ShipmentStatus newStatus;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task HandleSearchKeyDown(KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter")
+            await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        isLoading = true;
+        try
+        {
+            shipments = await ShipmentService.GetAllShipmentsAsync(statusFilter, searchTerm);
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void StartEdit(Shipment s)
+    {
+        editingShipmentId = s.Id;
+        newStatus = s.Status;
+    }
+
+    private void CancelEdit()
+    {
+        editingShipmentId = null;
+    }
+
+    private async Task SaveStatus(Shipment s)
+    {
+        await ShipmentService.UpdateShipmentStatusAsync(s.Id, newStatus);
+        s.Status = newStatus;
+        if (newStatus == ShipmentStatus.Delivered)
+            s.ActualDelivery = DateTime.UtcNow;
+        editingShipmentId = null;
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-info text-dark",
+        ShipmentStatus.PickedUp => "bg-secondary",
+        ShipmentStatus.Pending => "bg-warning text-dark",
+        ShipmentStatus.Delayed => "bg-danger",
+        ShipmentStatus.Cancelled => "bg-dark",
+        _ => "bg-secondary"
+    };
+}
+

